INSERT INTO design_features VALUES(1,'Artificial Gravity','feature',NULL,1,'Provides shipboard gravity equivalent to 1G. Crew suffer no zero-G penalties. Denoted ASV in Occ stat.');
INSERT INTO design_features VALUES(2,'Winged','feature',7,0,'Aerodynamic lifting surfaces. Required for atmospheric gliding and landing. Gives separate air Handling/SR.');
INSERT INTO design_features VALUES(3,'Sealed','switch',7,0,'Hull is fully airtight with airlocks. Standard for spacecraft.');
INSERT INTO design_features VALUES(4,'Automation','switch',7,0,'Reduces or eliminates workspace requirements. Cost varies.');
INSERT INTO design_features VALUES(5,'Exposed Radiators','switch',7,0,'Ship radiates waste heat efficiently but radiators are a combat vulnerability.');
INSERT INTO ships VALUES(1,NULL,NULL,'Star Flower',1,1,NULL,11,1,8,1,70,-1,5,13,2.0,NULL,1,0,1000.0,301.0,7,13,1,0,7,7,7,'2×',44500000.0,0,0,NULL,NULL,unistr('Fast tramp freighter built for frontier operations in regions with primitive port facilities. Its reactionless drives produce enough thrust to lift from a planetary surface — making it independent of starport infrastructure. The class has a well-earned reputation for attracting smugglers, independent operators, and the occasional slaver.\u000a\u000a> *"My first billet was chief engineer on the Rose of Rigel. The captain was a smuggler and a slaver — for some reason this class of ship tends to attract an unsavoury element."*\u000a> — Captain Zeke Morrigan\u000a\u000a**Crew (7):** Captain/navigator, pilot, chief engineer, comm/sensor operator (doubles as gunner when needed), engine room technician, steward, medic.\u000a\u000aSM+8 streamlined hull; 1,000 tons loaded; 75 yards long. Equipped with artificial gravity. Top atmospheric speed 3,500 mph.'),NULL,NULL);
INSERT INTO ships VALUES(2,NULL,NULL,'Midnight Sun',2,1,NULL,9,0,7,1,50,-1,5,12,3.0,2.600000000000000088,0,0,300.0,11.59999999999999965,2,8,0,1,2,2,0,NULL,3660000.0,0,0,NULL,NULL,unistr('Two-stage rocket designed to lift a crew from an Earth-gravity world to high orbit. The 300-ton first stage (booster) carries a 100-ton orbiter in its front hull. The booster falls away after accelerating the stack to 2.6 mps delta-V; the orbiter''s own chemical engine adds a further 3.4 mps, giving a total delta-V of 6 mps — sufficient to reach low orbit.\u000a\u000a> *"First time I went into space was aboard one of these relics, before they got the beanstalk up. 3G acceleration is not fun when you''re five years old."*\u000a> — Maya Bright\u000a\u000a**Crew:** Pilot and co-pilot (in orbiter control room).'),NULL,NULL);
INSERT INTO ships VALUES(3,NULL,NULL,'Midnight Sun',2,1,2,9,0,6,1,30,0,4,12,3.0,3.399999999999999912,0,0,100.0,11.40000000000000035,2,12,0,1,2,2,0,NULL,1610000.0,0,0,NULL,NULL,'Second stage of the Midnight Sun stack; also operable as a standalone vehicle. Winged design feature gives full atmospheric flight capability (Air Handling/SR: +4/5). Carries 12 passengers in airliner seating plus 10 tons of cargo. Expendable fuel tanks (30 tons central hull + 30 tons rear hull) provide 3.4 mps delta-V.',NULL,NULL);
