INSERT INTO ship_system_catalog VALUES(1,'Armor, Ice','Armor',0,0,'HULL',0,'Armoury (Vehicle Armor) −4','Semi-ablative. Not for SM+5–7 or streamlined hulls. Cost negligible.');
INSERT INTO ship_system_catalog VALUES(2,'Armor, Stone','Armor',0,0,'HULL',0,'Masonry','Semi-ablative. Not for SM+5–6 or streamlined hulls. Cost negligible.');
INSERT INTO ship_system_catalog VALUES(3,'Armor, Steel','Armor',7,0,'HULL',0,'Armoury (Vehicle Armor)',NULL);
INSERT INTO ship_system_catalog VALUES(4,'Armor, Light Alloy','Armor',7,0,'HULL',0,'Armoury (Vehicle Armor)','Aerospace-grade aluminium or titanium alloys.');
INSERT INTO ship_system_catalog VALUES(5,'Armor, Metallic Laminate','Armor',8,0,'HULL',0,'Armoury (Vehicle Armor)','Titanium/aluminium/beryllium with carbon or ceramic fibres.');
INSERT INTO ship_system_catalog VALUES(6,'Armor, Advanced Metallic Laminate','Armor',9,0,'HULL',0,'Armoury (Vehicle Armor)','Carbon nanotubes or boron nanotubes reinforce the alloy.');
INSERT INTO ship_system_catalog VALUES(7,'Armor, Nanocomposite','Armor',10,0,'HULL',0,'Armoury (Vehicle Armor)','Ultra-strength carbon/boron nanotube-reinforced polymers.');
INSERT INTO ship_system_catalog VALUES(8,'Armor, Organic','Armor',10,0,'HULL',0,'Carpentry / Biotechnology','Low-cost biotech: space-adapted wood, living tissue, living bioplastic. DR halved vs burning/corrosion.');
INSERT INTO ship_system_catalog VALUES(9,'Armor, Diamondoid','Armor',11,0,'HULL',0,'Armoury (Vehicle Armor)','Nano-fabricated diamondoid, fullerites, or cubic boron nitride.');
INSERT INTO ship_system_catalog VALUES(10,'Armor, Exotic Laminate','Armor',12,0,'HULL',0,'Armoury (Vehicle Armor)','Ultra-hard materials with high-density exotic matter laminate.');
INSERT INTO ship_system_catalog VALUES(11,'Cargo Hold','Cargo',7,0,'ANY',0,'Mechanic (Vehicle Type)','Options: Refrigerated (+$0.5K/ton), Shielded (0.5t shielded per ton sacrificed, +$4K/ton).');
INSERT INTO ship_system_catalog VALUES(12,'Passenger Seating','Cargo',7,0,'ANY',0,'Mechanic (Life Support)','Airliner seats with 24h limited life support.');
INSERT INTO ship_system_catalog VALUES(13,'Habitat','Cargo',7,0,'ANY',0,'Mechanic (Life Support)','Long-term quarters. Cabins exchangeable 1:1 for bunkrooms/cells; luxury cabin=2 cabins; 1 cabin=5t steerage cargo.');
INSERT INTO ship_system_catalog VALUES(14,'Open Space','Cargo',7,0,'ANY',0,'Housekeeping / Gardening','Pressurised hall: auditorium, farm, pool, garden. 20 areas = 1 acre. Can provide food.');
INSERT INTO ship_system_catalog VALUES(15,'Hangar Bay','Cargo',7,0,'HULL',0,'Mechanic (Vehicle Type)','Stores/launches/recovers craft. Can also carry roll-on/roll-off cargo.');
INSERT INTO ship_system_catalog VALUES(16,'Control Room','Control',7,0,'ANY',0,'Electronics Repair (Computers)','Includes basic comm/sensor array and hardened computer network.');
INSERT INTO ship_system_catalog VALUES(17,'Engine Room','Control',7,0,'ANY',0,'Mechanic (Vehicle Type)','Tools and parts for maintenance. Not required SM+10+. Lowers HT if absent on SM+5–9.');
INSERT INTO ship_system_catalog VALUES(18,'Comm/Sensor Array, Enhanced','Control',7,0,'HULL',0,'Electronics Repair (Comm/Sensors)','Larger multi-function phased array. Cost 1× base.');
INSERT INTO ship_system_catalog VALUES(19,'Comm/Sensor Array, Science','Control',7,0,'HULL',0,'Electronics Repair (Comm/Sensors)','Adds astronomical and physics survey instruments. Cost 5× base.');
INSERT INTO ship_system_catalog VALUES(20,'Comm/Sensor Array, Tactical','Control',7,0,'HULL',0,'Electronics Repair (Comm/Sensors)','Active jamming; can overcome Defensive ECM. Cost 5× base.');
INSERT INTO ship_system_catalog VALUES(21,'Comm/Sensor Array, Multipurpose','Control',7,0,'HULL',0,'Electronics Repair (Comm/Sensors)','Combines science and tactical functions. Cost 10× base.');
INSERT INTO ship_system_catalog VALUES(22,'Defensive ECM','Control',7,0,'ANY',0,'Electronics Repair (EW)','−2 to ranged attacks on vessel. Max 3 installed. Only vs same-or-lower TL attackers.');
INSERT INTO ship_system_catalog VALUES(23,'External Clamp','Control',7,0,'HULL',0,'Mechanic (Vehicle Type)','Grapples and attaches to another vessel or object.');
INSERT INTO ship_system_catalog VALUES(24,'Robot Arm','Control',8,0,'HULL',0,'Mechanic (Robotics)',NULL);
INSERT INTO ship_system_catalog VALUES(25,'Robot Leg','Control',9,0,'HULL',1,'Mechanic (Robotics)','High-energy. Allows walking on surfaces.');
INSERT INTO ship_system_catalog VALUES(26,'Cloaking Device','Control',NULL,1,'ANY',1,'Electronics Repair (EW)','Superscience stealth. −10 to detection. Deactivates if weapons fired or reaction drive used.');
INSERT INTO ship_system_catalog VALUES(27,'Power Plant, Fuel Cell','Power',7,0,'ANY',0,'Mechanic (Fuel Cell)','Provides 1 PP. Internal fuel: 3h (TL7), 8h (TL8), 12h (TL9), 24h (TL10+).');
INSERT INTO ship_system_catalog VALUES(28,'Power Plant, MHD Turbine','Power',9,0,'ANY',0,'Mechanic (MHD Turbine)','Provides 2 PP. Internal fuel: 6h (TL9), 12h (TL10+). Double fuel cell cost.');
INSERT INTO ship_system_catalog VALUES(29,'Power Plant, Fission Reactor','Power',8,0,'ANY',0,'Mechanic (Fission)','Provides 1 PP. Fuel: 25yr (TL8), 50yr (TL9), 75yr (TL10+).');
INSERT INTO ship_system_catalog VALUES(30,'Power Plant, Fusion Reactor','Power',9,0,'ANY',0,'Mechanic (Fusion)','Provides 2 PP. Fuel: 50yr (TL9), 200yr (TL10), 600yr (TL11), 1500yr (TL12). Min SM+10 at TL9.');
INSERT INTO ship_system_catalog VALUES(31,'Power Plant, Antimatter Reactor','Power',10,0,'ANY',0,'Mechanic (Antimatter)','Provides 4 PP. Internal fuel: 2yr (TL10), 20yr (TL11), 200yr (TL12). Explodes if damaged.');
INSERT INTO ship_system_catalog VALUES(32,'Power Plant, Super Fusion Reactor','Power',11,0,'ANY',0,'Mechanic (Fusion)','Provides 4 PP. Fuel: 400yr (TL11), 1000yr (TL12). Muon-catalysed or black hole catalysed.');
INSERT INTO ship_system_catalog VALUES(33,'Power Plant, Total Conversion','Power',12,1,'ANY',0,'Mechanic (Total Conversion)','Superscience. Provides 5 PP. Effectively unlimited endurance.');
INSERT INTO ship_system_catalog VALUES(34,'Solar Panel Array','Power',7,0,'HULL',0,'Mechanic (Electrical)','Generates power from sunlight. Performance drops with distance from star.');
INSERT INTO ship_system_catalog VALUES(35,'Ramscoop','Power',10,0,'FRONT',0,'Mechanic (High-Performance Spacecraft)','Scoops interstellar hydrogen as reaction mass. Unlimited delta-V if fast enough.');
