INSERT INTO ship_system_catalog VALUES(61,'Reactionless Engine, Super','Reactionless Engine',11,1,'REAR',1,'Mechanic (Contragravity)','Superscience.');
INSERT INTO ship_system_catalog VALUES(62,'Reactionless Engine, Subwarp','Reactionless Engine',NULL,1,'REAR',1,'Mechanic (Contragravity)','Superscience.');
INSERT INTO ship_system_catalog VALUES(63,'FTL, Stardrive Engine','FTL',NULL,1,'ANY',1,'Mechanic (FTL)','Superscience. Hyperdrive, jump, or warp — GM chooses type.');
INSERT INTO ship_system_catalog VALUES(64,'FTL, Super Stardrive Engine','FTL',NULL,1,'ANY',1,'Mechanic (FTL)','Superscience. Higher FTL rating.');
INSERT INTO ship_system_catalog VALUES(65,'FTL, Jump Gate','FTL',NULL,1,'HULL',1,'Electronics Repair (MT)','Superscience. Fixed wormhole portal. Multiple in same section combine capacity.');
INSERT INTO ship_system_catalog VALUES(66,'Weapon, Major Battery','Weapon',7,0,'HULL',1,NULL,'Turret or fixed mount. Largest shipboard weapons.');
INSERT INTO ship_system_catalog VALUES(67,'Weapon, Medium Battery','Weapon',7,0,'HULL',1,NULL,NULL);
INSERT INTO ship_system_catalog VALUES(68,'Weapon, Secondary Battery','Weapon',7,0,'HULL',1,NULL,NULL);
INSERT INTO ship_system_catalog VALUES(69,'Weapon, Tertiary Battery','Weapon',7,0,'HULL',1,NULL,'Can sacrifice cargo capacity for weapons.');
INSERT INTO ship_system_catalog VALUES(70,'Weapon, Spinal Battery','Weapon',7,0,'SPECIAL',1,NULL,'Runs the length of the ship spine. Special placement rules.');
INSERT INTO ship_system_catalog VALUES(71,'Industrial, Factory: Fabricator','Industrial',8,0,'ANY',1,'Mechanic (Machine Tools)','High-tech machine shop. Needs component parts at 40% of good value.');
INSERT INTO ship_system_catalog VALUES(72,'Industrial, Factory: Robofac','Industrial',10,0,'ANY',1,'Mechanic (Robotics)','Self-operating fabricator. Machinist-14 skill. 2× fabricator cost.');
INSERT INTO ship_system_catalog VALUES(73,'Industrial, Factory: Nanofactory','Industrial',11,0,'ANY',1,'Mechanic (Nanomachines)','Raw materials in, finished goods out. 4× fabricator cost.');
INSERT INTO ship_system_catalog VALUES(74,'Industrial, Factory: Replicator','Industrial',12,1,'ANY',1,'Electronics Repair (MT)','Superscience. Transmutes elements. 20× fabricator cost.');
INSERT INTO ship_system_catalog VALUES(75,'Industrial, Mining System','Industrial',7,0,'ANY',1,'Mechanic (Mining)','Extracts ore or converts ice/rock. Needs Mechanic (Mining) supervisor.');
INSERT INTO ship_system_catalog VALUES(76,'Industrial, Chemical Refinery','Industrial',7,0,'ANY',1,'Mechanic (Refineries)','Processes ice into hydrogen/oxygen rocket fuel.');
INSERT INTO ship_system_catalog VALUES(77,'Fuel Tank','Utility',7,0,'ANY',0,'Mechanic (Vehicle Type)','Reaction mass for reaction drives. Delta-V multiplier for 6+ tanks.');
INSERT INTO ship_system_catalog VALUES(78,'Jet Engine','Utility',7,0,'REAR',0,'Mechanic (Jet Engines)','Turbojet/scramjet. Atmosphere only (0.1+ atm). 1G per engine. Uses 1 fuel tank/half-hour (TL7) or hour (TL8+).');
INSERT INTO ship_system_catalog VALUES(79,'Soft-Landing System','Utility',7,0,'HULL',0,'Mechanic (Vehicle Type)','Retrorockets or airbags for gentle planetary landing.');
INSERT INTO ship_system_catalog VALUES(80,'Space Sails: Lightsail','Utility',9,0,'HULL',0,'Mechanic (High-Performance Spacecraft)','Photon pressure. Laser-pushed variants reach near-c. Delta-V notation /c.');
INSERT INTO ship_system_catalog VALUES(81,'Space Sails: Magsail','Utility',9,0,'HULL',0,'Mechanic (High-Performance Spacecraft)','Magnetic braking on stellar wind. Useful for deceleration. Delta-V notation /c.');
INSERT INTO ship_system_catalog VALUES(82,'Upper Stage','Utility',7,0,'SPECIAL',0,'Mechanic (Vehicle Type)','A complete spacecraft in the front hull of a multi-stage vehicle.');
INSERT INTO ship_system_catalog VALUES(83,'Reconfigurable System','Utility',11,1,'SPECIAL',0,'Mechanic (Vehicle Type)','Superscience. Can change function between missions.');
INSERT INTO ship_system_catalog VALUES(84,'Contragravity Lifter','Superscience',NULL,1,'ANY',1,'Mechanic (Contragravity)','Nullifies local gravity. Treated as reactionless drive. Can land/take off from any normal planet up to 10G.');
INSERT INTO ship_system_catalog VALUES(85,'Force Screen, Light','Superscience',11,1,'ANY',1,'Armoury (Force Shields)','Semi-ablative dDR around entire vessel. Regenerates 10% lost dDR/second while powered.');
INSERT INTO ship_system_catalog VALUES(86,'Force Screen, Heavy','Superscience',12,1,'ANY',1,'Armoury (Force Shields)','Can use 2nd PP to double dDR. Otherwise same as light screen.');
INSERT INTO ship_system_catalog VALUES(87,'Stasis Web','Superscience',12,1,'ANY',1,NULL,'Superscience. Freezes target in stasis field.');
